SELECT jobid, version, stepid, seq1, seq2, seq3, column_name, update_val, status
FROM cotdl.tbl_piisteptableupdate
WHERE jobid = #{jobid, jdbcType=VARCHAR}
  AND version = (
	SELECT MAX(version)
	FROM cotdl.tbl_piijob
	WHERE jobid = #{jobid, jdbcType=VARCHAR}
	  and phase='CHECKIN' and status='ACTIVE'
)


select jobid, version, stepid, seq1, seq2, seq3, column_name, update_val, status 
